package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.Appendable;
import java.io.Closeable;
import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVPrinterTest {

    private Appendable appendable;
    private CSVFormat format;
    private CSVPrinter printer;

    @BeforeEach
    void setUp() {
        appendable = mock(Appendable.class);
        format = mock(CSVFormat.class);
        printer = new CSVPrinter(appendable, format);
    }

    @Test
    void close_whenOutIsCloseable_shouldCloseOut() throws IOException {
        Closeable closeable = mock(Closeable.class);
        CSVPrinter printerWithCloseable = new CSVPrinter(closeable, format);

        printerWithCloseable.close();

        verify(closeable, times(1)).close();
    }

    @Test
    void close_whenOutIsNotCloseable_shouldNotThrow() {
        assertDoesNotThrow(() -> printer.close());
    }
}
